INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-f3743df6-moex-00012', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-114-13504c0c', 'sub-generalpolice-f3743df6-02', NULL, 'single_choice', '「2022 年，聊天機器人 ChatGPT 的出現引領了全球人工智慧的熱潮，但也帶來了 人們對就業和倫理的擔憂。關於就業，研究表明，在未來幾十年內，真正被取代的 工作僅占所有工作的10％左右。並非所有工作都會被完全自動化，而是某些特定任 務會被自動化。重要的是，我們需要關注人們是否具備與機器協作的技能，並提供 技能再造和適應新職場的支持。關於倫理問題，面對強大的人工智慧系統時，需要 思考如何合理應用它，避免不良利用。如何制定合理的使用原則，確保訓練和應用 符合實際需求。同時，也要關注可能的誤用，包括無意的落差和有意的濫用。解決 這些就業和倫理問題，需要的不僅是電腦工程專家，還需要涉及多個領域的專家， 如社會科學家、倫理學者和哲學家等。」 根據上文，下列選項何者最符合文意？', '["解決就業和倫理問題，端賴全球電腦工程專家的共同努力", "研究表明，在未來幾十年內，所有工作都會被完全自動化取代", "人工智慧帶來就業和倫理的擔憂，需要關注技能再造和適應新職場", "強大人工智慧系統的應用，需要遵循傳統的使用原則，以防止不良利用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:42+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "305", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00013', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-114-13504c0c', 'sub-generalpolice-f3743df6-02', NULL, 'single_choice', '「大企業為什麼凡事都得曠日廢時？主要是官僚作風的無形掣肘——每件事都必 須按照規定與流程完成。許多企業主管表示希望從官僚作風轉變為『菁英精神』， 置人才與構想於一切之上。但事實證明，菁英精神可以跟官僚作風一樣拖拖拉拉， 一樣著眼於內部。我們在最古老的菁英體系——大學——中工作，儘管我們痛恨規 則，卻熱愛事事針鋒相對。所以，你需要的是著重於行動。在實務上，簡化公司正 式流程、減少跨部門委員會的數量與規模，以靈活、敏捷的小型團隊模式取而代之； 這些團隊獲得授權，可以快速直接因應顧客需求。打比方，你不妨將這些團隊想像 成軍方派入敵區作戰的特殊部隊。」 根據上文，下列敘述何者正確？', '["官僚作風可以靈活地省略各種規定與流程", "菁英精神重視人才與構想，而且行動迅速", "菁英精神未必能克服官僚作風在處理事務上的效率問題", "團體組織更見效率，流程簡化時擴大跨部會委員會規模"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:42+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "305", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('generalpolice-f3743df6-moex-00014', 'generalpolice-f3743df6', 'generalpolice-f3743df6-moex-114-4b605adb', 'sub-generalpolice-f3743df6-03', NULL, 'essay', '甲為知名藥品公司，希望於我國註冊單一顏色商標，以藍色指定商品包
